-- Seed справочника типовых работ (work_types) + связь work_orders.work_type_id.
-- Идемпотентно: CREATE TABLE IF NOT EXISTS, ADD COLUMN IF NOT EXISTS, ON CONFLICT (name) DO NOTHING.
-- Запуск в Railway psql. Даёт тексты для разделов бланка наряда-допуска.

BEGIN;

CREATE TABLE IF NOT EXISTS work_types (
    id VARCHAR PRIMARY KEY,
    name VARCHAR NOT NULL UNIQUE,
    content TEXT,
    conditions TEXT,
    hazards TEXT,
    sys_restraint TEXT,
    sys_fall_arrest TEXT,
    sys_rescue TEXT,
    process_measures TEXT,
    norms TEXT,
    active BOOLEAN NOT NULL DEFAULT true
);

ALTER TABLE work_orders ADD COLUMN IF NOT EXISTS work_type_id VARCHAR REFERENCES work_types(id);

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Армирование стен/колонн/перекрытий$$,
  $$Приёмка и сортировка арматуры; заготовка и укрупнительная сборка каркасов в отведённых местах; подача заготовок к месту установки; установка каркасов и сеток в проектное положение; вязка узлов вязальной проволокой, установка фиксаторов защитного слоя, монтаж закладных деталей; выверка геометрии каркаса перед бетонированием.$$,
  $$Работа с инвентарных подмостей/лесов с настилом и ограждением не менее 1,1 м; перемещение по уложенной арматуре — только по настилам шириной не менее 0,6 м. Заготовка и укрупнительная сборка — в специально отведённых местах. У края перекрытия и неогражденных перепадов — удерживающая система с креплением стропа за надёжные неподвижные металлоконструкции; страховочная система с непрерывным закреплением. Запрещены работы при ветре 15 м/с и более, гололёде, грозе, тумане.$$,
  $$Падение работника с высоты; падение предметов (арматура, инструмент, проволока); острые кромки, торцы и заусенцы арматуры (порезы, проколы); неровные/скользкие поверхности каркаса; движущиеся части кранов/подъёмников при подаче каркасов; поражение электротоком; неблагоприятные погодные и температурные факторы (обледенение, низкая температура, ветер); отказ/неисправность СИЗ; недостаточная освещённость (полярная ночь).$$,
  $$Удерживающая привязь с удерживающим стропом (регулятор длины), присоединённым к анкерной точке/надёжной неподвижной металлоконструкции, исключающим выход работника в зону возможного падения.$$,
  $$Страховочная привязь с точками крепления А + строп с амортизатором (или СИЗ втягивающего типа), присоединяемый к анкерному устройству/анкерной линии; обеспечение непрерывности страховки при перемещении.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль защиты от порезов и проколов об арматуру (перчатки, колпачки на торцах стержней).
Контроль устойчивости арматурных каркасов при установке и до начала бетонирования.$$,
  $$782н п. 7, 45, 65, 116, 131, 136, 137, 156, Прил. № 12; 883н п. 200; СП 70.13330.2012 разд. 5.16; СНиП 12-04-2002 п. 7.2.7, 7.2.13; ГОСТ 10922-2012; ГОСТ Р 58208-2018; ГОСТ 12.0.003-2015.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Монтаж опалубки$$,
  $$Приёмка, осмотр и смазка щитов; укрупнительная сборка панелей на земле; строповка и подача элементов краном; установка щитов в проектное положение, фиксация подкосами, стяжками, замками; выверка вертикальности/горизонтальности; устройство рабочих настилов и ограждений.$$,
  $$Крупнощитовые панели собираются на земле и устанавливаются подъёмной техникой, фиксируются подкосами. Рабочие настилы — шириной не менее 0,8 м с ограждениями. Металлические опалубки оборудуются скобами для закрепления систем безопасности. Доступ — с лесов/подмостей/вышек-тур; при работе с люльки автогидроподъёмника крепление стропа за анкерные точки ограждения люльки. Ограничение доступа в опасную зону, ограждение и знаки безопасности.$$,
  $$Падение с высоты; падение элементов опалубки и инструмента; опрокидывание/потеря устойчивости опалубки и средств подмащивания; движущиеся части крана (подача щитов); защемление, удары щитами; острые кромки; поражение электротоком; погодные/температурные факторы; отказ СИЗ; недостаточная видимость.$$,
  $$Удерживающая привязь + удерживающий строп к анкерной точке/скобам опалубки или неподвижным металлоконструкциям, ограничивающий перемещение вне зоны падения.$$,
  $$Страховочная привязь + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству; при работе в люльке подъёмника — крепление за анкерные точки люльки.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль устойчивости и раскрепления щитов (подкосы, стяжки) до снятия строповки.
Недопущение нахождения людей под перемещаемыми и нераскреплёнными панелями.$$,
  $$782н п. 7, 45, 65, 114, 116, 137, 194, Прил. № 12; 883н п. 186, 188; СП 70.13330.2012 разд. 5.17; СНиП 12-04-2002 п. 7.2.3; ГОСТ 34329-2017; ГОСТ Р 58208-2018; ГОСТ 12.0.003-2015.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Демонтаж (распалубка) опалубки$$,
  $$Проверка достижения бетоном распалубочной прочности; получение разрешения производителя работ; снятие стяжек, подкосов, замков; поярусная разборка сверху вниз; спуск элементов опалубки; очистка, сортировка и складирование щитов.$$,
  $$Демонтаж — по наряду-допуску, не менее чем двумя работниками под наблюдением бригадира/ИТР, только после достижения бетоном заданной прочности и с разрешения производителя работ. Меры против случайного падения элементов и обрушения поддерживающих лесов; оставление достаточного числа опор. Опасная зона ограждается, вывешиваются знаки; под зоной — защитный козырёк. Работа с подмостей/лесов/люльки подъёмника с креплением страховочной/удерживающей системы.$$,
  $$Падение с высоты; падение/обрушение элементов опалубки и поддерживающих конструкций; удары падающими деталями; острые кромки, гвозди, крепёж; движущиеся части крана; погодные/температурные факторы; отказ СИЗ; недостаточная освещённость.$$,
  $$Удерживающая привязь + удерживающий строп к анкерной точке/неподвижной металлоконструкции, ограничивающий доступ к краю перепада.$$,
  $$Страховочная привязь + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству/анкерной линии с обеспечением непрерывности страховки.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль, что элементы опалубки не падают самопроизвольно; поярусная разборка сверху вниз.
Сохранение необходимого числа опор до набора прочности; работа не менее чем вдвоём под наблюдением.$$,
  $$782н п. 7, 45, 65, 116, 136, 137, 156, Прил. № 12; 883н п. 187, 210, 211; СП 70.13330.2012 разд. 5.17; ГОСТ Р 58208-2018; ГОСТ 12.0.003-2015.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Бетонирование конструкций$$,
  $$Приёмка бетонной смеси; распределение по опалубке (с распределительной стрелы автобетононасоса/бетоновода); укладка слоями; уплотнение глубинными/поверхностными электровибраторами; заглаживание поверхности; устройство рабочих швов.$$,
  $$Заливка и уплотнение вибраторами — с инвентарных навесных площадок с ограждением не менее 1,1 м; приёмка и уплотнение стоя на опалубке запрещены. На поверхностях с уклоном более 20° — обязательно системы безопасности работ на высоте. Электровибраторы не перемещать за кабель, при перерывах отключать. Крепление удерживающей/страховочной системы за неподвижные металлоконструкции или анкерные точки. Погодные ограничения по п. 45 Правил 782н.$$,
  $$Падение с высоты; падение предметов; движущиеся части (бетононасос, бетоновод, вибратор); поражение электротоком (вибратор, электрооборудование); химическое воздействие бетонной смеси (щёлочь) на кожу/глаза; повышенный шум и вибрация; скользкие поверхности; погодные/температурные факторы; отказ СИЗ.$$,
  $$Удерживающая привязь + удерживающий строп к анкерной точке/неподвижной металлоконструкции для работы у края без выхода в зону падения.$$,
  $$Страховочная привязь + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству; на навесных площадках — совместно с ограждением 1,1 м.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль устойчивого положения бетоновода и распределительной стрелы автобетононасоса.
Отключение вибратора в перерывах; недопущение приёмки и уплотнения смеси стоя на опалубке.$$,
  $$782н п. 7, 45, 65, 116, 136, 137, Прил. № 12; 883н п. 186, 197, 198, 213; СП 70.13330.2012 разд. 5.3–5.11; ГОСТ 7473-2010; ГОСТ Р 58208-2018; ГОСТ 12.0.003-2015.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Уход за бетоном (в т.ч. электропрогрев)$$,
  $$Укрытие поверхности плёнкой/матами; увлажнение в тёплое время; в зимнее время — монтаж греющих проводов/электродов на арматурные каркасы, присоединение трансформатора, контроль температуры, снятие проводов после прогрева; наблюдение за прогреваемой зоной.$$,
  $$Монтаж и присоединение электрооборудования прогрева — электротехническим персоналом с группой по электробезопасности не ниже III. Зона электропрогрева ограждается, оборудуется световой сигнализацией и знаками безопасности, под постоянным наблюдением; посторонним вход запрещён. Работа на высоте — с подмостей/лесов с ограждением, при риске падения — с удерживающей/страховочной системой. Учитывать полярные условия Мурманска (обледенение, низкие температуры).$$,
  $$Падение с высоты; поражение электротоком (электропрогрев, повышенное напряжение); термические ожоги/повышенная температура прогреваемых элементов; падение предметов; скользкие/обледенелые поверхности; погодные/температурные факторы; отказ СИЗ; недостаточная освещённость.$$,
  $$Удерживающая привязь + удерживающий строп к анкерной точке/неподвижной металлоконструкции, ограничивающий доступ к краю.$$,
  $$Страховочная привязь + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству с непрерывной страховкой.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль ограждения, сигнализации и знаков зоны электропрогрева.
Электрические операции — персоналом с группой по электробезопасности не ниже III; контроль температуры прогрева.$$,
  $$782н п. 7, 45, 65, 116, 136, 137, Прил. № 12; 883н п. 201, 215; СП 70.13330.2012 разд. 5.11, Прил. П; СНиП 12-04-2002 п. 7.2.14; ГОСТ 12.0.003-2015; ГОСТ Р 58208-2018.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Приёмка бетонной смеси с автобетононасоса$$,
  $$Подготовка и осмотр рабочей зоны и бетоновода; приём бетонной смеси из концевого рукава распределительной стрелы; управление рукавом; распределение смеси по захваткам опалубки; контроль устойчивого положения автобетононасоса; связь с машинистом.$$,
  $$Подача смеси — только при устойчивом положении автобетононасоса на выносных опорах. Надёжная звуковая/визуальная связь машиниста и бетонщиков. Запрещён доступ посторонних в опасную зону (радиус поворота стрелы плюс 5 м; 3 м в обе стороны приёмного бункера). Запрещается удлинять концевой шланг, работать под стрелой, перегибать шланг. Работа приёмщика — с навесной площадки с ограждением не менее 1,1 м, с креплением удерживающей/страховочной системы.$$,
  $$Падение с высоты; опрокидывание автобетононасоса (потеря устойчивости); движущиеся части (распределительная стрела, рукав, задвижки); выброс смеси/срыв рукава под давлением; химическое воздействие бетонной смеси; шум; поражение электротоком; падение предметов; погодные/температурные факторы; отказ СИЗ.$$,
  $$Удерживающая привязь + удерживающий строп к анкерной точке/неподвижной металлоконструкции, ограничивающий перемещение вне зоны падения.$$,
  $$Страховочная привязь + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству; при работе с навесной площадки — совместно с ограждением 1,1 м.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль устойчивости автобетононасоса на выносных опорах; соблюдение границ опасной зоны стрелы.
Связь с машинистом; запрет нахождения под стрелой и удлинения концевого шланга.$$,
  $$782н п. 7, 45, 65, 116, 136, 137, Прил. № 12; 883н п. 186, 197; Рекомендации по укладке бетонной смеси автобетононасосом; ГОСТ 12.0.003-2015; ГОСТ Р 58208-2018.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Работы на высоте на монолитных конструкциях (общие)$$,
  $$Перемещение по монолитным конструкциям и средствам подмащивания; подготовка рабочих мест; вспомогательные операции при армировании, опалубке, бетонировании; установка/снятие ограждений, знаков безопасности, защитных настилов и козырьков.$$,
  $$Защита от временной неустойчивости сооружения, опалубки и опорных креплений. Безопасный доступ — приставные лестницы, подмости, инвентарные леса, вышки-туры, люльки автогидроподъёмника. При работе с лестниц/подмостей — крепление страховочной системы за неподвижные металлоконструкции; с люльки подъёмника — за анкерные точки ограждения люльки. Непрерывное закрепление при перемещении. Определение и ограждение границ опасных зон. Погодные ограничения по п. 45 Правил 782н.$$,
  $$Падение с высоты; падение предметов; неустойчивость конструкций/средств подмащивания; острые кромки арматуры; движущиеся части машин; поражение электротоком; неровные/скользкие/обледенелые поверхности; погодные и температурные факторы; недостаточная видимость (полярная ночь); отказ/неисправность СИЗ.$$,
  $$Удерживающая привязь + удерживающий строп с регулятором длины к анкерной точке/неподвижной металлоконструкции.$$,
  $$Страховочная привязь с точками А + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству/анкерной линии; непрерывность страховки при перестёжке.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Контроль устойчивости конструкций и средств подмащивания.
Контроль границ опасных зон и целостности ограждений.$$,
  $$782н п. 7, 45, 65, 116, 131, 136, 137, 156, 194, Прил. № 12; 883н разд. IX; СНиП 12-04-2002 разд. 7; ГОСТ Р 58208-2018; ГОСТ 12.0.003-2015.$$
) ON CONFLICT (name) DO NOTHING;

INSERT INTO work_types (id, name, content, conditions, hazards, sys_restraint, sys_fall_arrest, sys_rescue, process_measures, norms) VALUES (
  gen_random_uuid()::text,
  $$Вязка/монтаж арматуры на высоте$$,
  $$Подача и приёмка арматурных стержней/каркасов на высоте; установка в проектное положение; вязка узлов вязальной проволокой/скрутками; установка фиксаторов и закладных деталей; выверка каркаса; при необходимости — резка/гибка стержней на месте.$$,
  $$Перемещение по уложенной арматуре — только по настилам шириной не менее 0,6 м. При отсутствии сплошного настила и ограждения — обязательное применение систем безопасности работ на высоте. Крепление страховочной системы за неподвижные несущие металлоконструкции/анкерные точки; с люльки подъёмника — за анкерные точки ограждения люльки. Непрерывность страховки при перестёжке. Работы прекращаются при ветре 15 м/с и более, гололёде, грозе, тумане.$$,
  $$Падение с высоты; падение арматуры/инструмента; острые кромки, торцы и заусенцы арматуры (порезы, проколы); неустойчивое положение на каркасе; движущиеся части крана/подъёмника; поражение электротоком; погодные/температурные факторы; недостаточная освещённость; отказ СИЗ.$$,
  $$Удерживающая привязь + удерживающий строп к анкерной точке/неподвижной металлоконструкции для ограничения перемещения вне зоны падения.$$,
  $$Страховочная привязь с точками А + строп с амортизатором/СИЗ втягивающего типа к анкерному устройству/анкерной линии с обеспечением непрерывности страховки.$$,
  $$Автогидроподъёмник для эвакуации работника из зоны работ; спасательный комплект с индивидуальным спусковым устройством (ИСУ, автоматическая скорость спуска не более 2 м/с) и спасательной петлёй; носилки, средства иммобилизации, аптечка первой помощи.$$,
  $$Контроль непрерывного закрепления страховочной системы при перемещении и перестёжке (без слабины).
Осмотр СИЗ от падения с высоты до и в процессе использования; при выявлении дефектов — немедленное изъятие из эксплуатации.
Постоянный контроль погодных условий; приостановка работ при ветре 15 м/с и более, гололёде, грозе, тумане, ухудшении видимости.
Поддержание ограждения опасной зоны и знаков безопасности; недопущение посторонних лиц в зону работ.
Контроль исправности средств подмащивания (лесов, подмостей, вышек-тур, люльки подъёмника) в течение смены.
Готовность средств спасения и эвакуации; поддержание связи в бригаде.
Перемещение только по настилам шириной не менее 0,6 м.
Контроль непрерывности страховки и защиты от порезов об арматуру.$$,
  $$782н п. 7, 45, 65, 116, 131, 136, 137, 156, 194, Прил. № 12; 883н п. 200; СНиП 12-04-2002 п. 7.2.7, 7.2.13; СП 70.13330.2012 разд. 5.16; ГОСТ 10922-2012; ГОСТ Р 58208-2018; ГОСТ 12.0.003-2015.$$
) ON CONFLICT (name) DO NOTHING;

COMMIT;
